class DynamicAwareRegistry<T>(private val static: Registry<T>): Registry<T> {
  private val dynamic = ConcurrentHashMap<ResourceLocation,T>()
  private val lock = ReentrantReadWriteLock()
  fun registerDynamic(name,T):T { writeLock { check conflict; assign id; dynamic[name]=T } }
  override fun get(name)= dynamic[name] ?: static.get(name)
  // implement other required methods similarly
}
